#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

struct Node{
    int l,r;
    int val,dat;
    int siz,sl,sr,isl,isr;
    int tr,ts,ti;
}a[N];

int n,q,tot,root;

int New(int val){
    tot++;
    a[tot].val=val,a[tot].dat=rand();
    a[tot].siz=1;
    if(val)
        a[tot].sr=a[tot].isl=1;
    else
        a[tot].sl=a[tot].isr=1;
    a[tot].tr=-1,a[tot].ts=a[tot].ti=0;
    return tot;
}

void Update(int p){
    if(!p)
        return;
    int tmp=(a[p].val?-1:1);
    a[p].siz=a[a[p].l].siz+1+a[a[p].r].siz;
    a[p].sl=max(a[a[p].l].sl+tmp-a[a[p].r].sr,0)+a[a[p].r].sl;
    a[p].sr=max(a[a[p].r].sr-tmp-a[a[p].l].sl,0)+a[a[p].l].sr;
    a[p].isl=max(a[a[p].l].isl-tmp-a[a[p].r].isr,0)+a[a[p].r].isl;
    a[p].isr=max(a[a[p].r].isr+tmp-a[a[p].l].isl,0)+a[a[p].l].isr;
}

void change_tag(int p,int tp,int val){
    if(!p)
        return;
    if(tp==0){
        a[p].tr=val;
        a[p].val=val;
        if(val==0)
            a[p].sl=a[p].isr=a[p].siz,a[p].sr=a[p].isl=0;
        else
            a[p].sr=a[p].isl=a[p].siz,a[p].sl=a[p].isr=0;
        a[p].ts=0;
        a[p].ti=0;
    }else if(tp==1){
        a[p].ts^=1;
        swap(a[p].sl,a[p].sr);
        swap(a[p].isl,a[p].isr);
        a[p].val^=1;
    }else{
        a[p].ti^=1;
        swap(a[p].sl,a[p].isl);
        swap(a[p].sr,a[p].isr);
        a[p].val^=1;
    }
}

void push_down(int p){
    if(!p)
        return;
    if(a[p].tr>=0){
        change_tag(a[p].l,0,a[p].tr);
        change_tag(a[p].r,0,a[p].tr);
        a[p].tr=-1;
    }
    if(a[p].ts){
        swap(a[p].l,a[p].r);
        change_tag(a[p].l,1,0);
        change_tag(a[p].r,1,0);
        a[p].ts=0;
    }
    if(a[p].ti){
        change_tag(a[p].l,2,0);
        change_tag(a[p].r,2,0);
        a[p].ti=0;
    }
}

int merge(int p,int q){
    if(!p)
        return q;
    if(!q)
        return p;
    if(a[p].dat>a[q].dat){
        push_down(p);
        a[p].r=merge(a[p].r,q);
        Update(p);
        return p;
    }else{
        push_down(q);
        a[q].l=merge(p,a[q].l);
        Update(q);
        return q;
    }
}

pair<int,int> split(int p,int k){
    if(k==a[p].siz)
        return make_pair(p,0);
    if(!k)
        return make_pair(0,p);
    push_down(p);
    pair<int,int> tmp;
    if(a[a[p].l].siz>=k){
        tmp=split(a[p].l,k);
        a[p].l=tmp.second,Update(p);
        return make_pair(tmp.first,p);
    }else{
        tmp=split(a[p].r,k-a[a[p].l].siz-1);
        a[p].r=tmp.first,Update(p);
        return make_pair(p,tmp.second);
    }
}

int cal(int p){
    return (a[p].sl+a[p].sr)/2+a[p].sl%2;
}

int main(){
    srand(time(NULL));
    char s[N];
    scanf("%d%d",&n,&q);
    scanf("%s",s+1);
    for(int i=1;i<=n;i++)
        root=merge(root,New(s[i]-'('));
    while(q--){
        int l,r;
        scanf("%s%d%d",s,&l,&r);
        if(s[0]=='R'){
            scanf("%s",s);
            pair<int,int> tmp=split(root,l-1);
            int x=tmp.first;
            tmp=split(tmp.second,r-l+1);
            change_tag(tmp.first,0,s[0]-'(');
            root=merge(x,merge(tmp.first,tmp.second));
        }else if(s[0]=='S'){
            pair<int,int> tmp=split(root,l-1);
            int x=tmp.first;
            tmp=split(tmp.second,r-l+1);
            change_tag(tmp.first,1,0);
            change_tag(tmp.first,2,0);
            root=merge(x,merge(tmp.first,tmp.second));
        }else if(s[0]=='I'){
            pair<int,int> tmp=split(root,l-1);
            int x=tmp.first;
            tmp=split(tmp.second,r-l+1);
            change_tag(tmp.first,2,0);
            root=merge(x,merge(tmp.first,tmp.second));
        }else{
            pair<int,int> tmp=split(root,l-1);
            int x=tmp.first;
            tmp=split(tmp.second,r-l+1);
            printf("%d\n",cal(tmp.first));
            root=merge(x,merge(tmp.first,tmp.second));
        }
    }
    return 0;
}
